import numpy as np

def sigmoid(z):
 return 1 / (1 + np.exp(-z))

def artificial_neuron(inputs, weights, bias):
 z = np.dot(inputs, weights) + bias
 return sigmoid(z)

# Example usage:
inputs = np.array([1, 2, 3])
weights = np.array([0.5, 0.6, 0.7])
bias = 0.8
output = artificial_neuron(inputs, weights, bias)
print(output)

#include <stdio.h>
#include <math.h>

double sigmoid(double z) {
 return 1 / (1 + exp(-z));
}

double artificial_neuron(double inputs[], double weights[], double bias, int n) {
 double z = 0;
 for (int i = 0; i < n; i++) {
 z += inputs[i] * weights[i];
 }
 z += bias;
 return sigmoid(z);
}

int main() {
 double inputs[] = {1, 2, 3};
 double weights[] = {0.5, 0.6, 0.7};
 double bias = 0.8;
 int n = 3;
 double output = artificial_neuron(inputs, weights, bias, n);
 printf("%f\n", output);
 return 0;
}
